<div class="flex items-center justify-between mb-6"><div><h3 class="text-lg font-semibold text-gray-800 dark:text-white"><?= htmlspecialchars($project['name']) ?></h3><p class="text-sm text-gray-500"><?= htmlspecialchars($project['client_name'] ?? '') ?></p></div><a href="/admin/projetos/<?= $project['id'] ?>/editar" class="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white text-sm font-medium rounded-lg transition">Editar</a></div><div class="grid grid-cols-1 lg:grid-cols-3 gap-6"><div class="lg:col-span-2 space-y-6"><div class="bg-white dark:bg-gray-800 rounded-xl p-5 border border-gray-100 dark:border-gray-700"><h4 class="font-semibold text-gray-800 dark:text-white mb-3">Tarefas (<?= count($tasks) ?>)</h4><div class="space-y-2"><?php foreach ($tasks as $t): ?><div class="flex items-center justify-between p-3 rounded-lg bg-gray-50 dark:bg-gray-900/50"><div class="flex items-center gap-3"><span class="w-2 h-2 rounded-full <?= $t['status'] === 'completed' ? 'bg-green-500' : ($t['status'] === 'in_progress' ? 'bg-yellow-500' : 'bg-gray-400') ?>"></span><span class="text-sm text-gray-700 dark:text-gray-300"><?= htmlspecialchars($t['title']) ?></span></div><span class="text-xs text-gray-500"><?= $t['assigned_name'] ?? '—' ?></span></div><?php endforeach; ?><?php if (empty($tasks)): ?><p class="text-sm text-gray-500 text-center py-4">Nenhuma tarefa.</p><?php endif; ?></div></div></div><div class="space-y-6"><div class="bg-white dark:bg-gray-800 rounded-xl p-5 border border-gray-100 dark:border-gray-700"><h4 class="font-semibold text-gray-800 dark:text-white mb-3">Info</h4><div class="space-y-3 text-sm"><div class="flex justify-between"><span class="text-gray-500">Status</span><span class="text-gray-800 dark:text-white font-medium"><?= $project['status'] ?></span></div><div class="flex justify-between"><span class="text-gray-500">Início</span><span class="text-gray-800 dark:text-white"><?= $project['start_date'] ? date('d/m/Y', strtotime($project['start_date'])) : '—' ?></span></div><div class="flex justify-between"><span class="text-gray-500">Prazo</span><span class="text-gray-800 dark:text-white"><?= $project['due_date'] ? date('d/m/Y', strtotime($project['due_date'])) : '—' ?></span></div><div class="flex justify-between"><span class="text-gray-500">Valor</span><span class="text-gray-800 dark:text-white"><?= $project['value'] ? 'R$ ' . number_format((float)$project['value'], 2, ',', '.') : '—' ?></span></div></div></div><div class="bg-white dark:bg-gray-800 rounded-xl p-5 border border-gray-100 dark:border-gray-700"><h4 class="font-semibold text-gray-800 dark:text-white mb-3">Equipe (<?= count($members) ?>)</h4><?php foreach ($members as $m): ?><div class="flex items-center gap-2 py-1"><div class="w-6 h-6 bg-purple-100 dark:bg-purple-900/30 rounded-full flex items-center justify-center text-xs text-purple-700 dark:text-purple-300 font-bold"><?= strtoupper(substr($m['name'], 0, 1)) ?></div><span class="text-sm text-gray-700 dark:text-gray-300"><?= htmlspecialchars($m['name']) ?></span></div><?php endforeach; ?><?php if (empty($members)): ?><p class="text-sm text-gray-500">Nenhum membro.</p><?php endif; ?></div></div></div>